const req = $('Init & Build Prompt').item.json;
const llmRes = $input.first().json;

let parsed;
try {
  parsed = JSON.parse(llmRes.choices[0].message.content);
} catch (e) {
  parsed = { strategies: [{ name: 'Fallback', query: (req.ctx.results?.career_goals?.inferred_roles?.[0] || 'Software Engineering') + ' Internship' }] };
}

return parsed.strategies.map(s => ({
  json: { ctx: req.ctx, strategy: s }
}));

const strategy = $input.first().json.strategy;
return [{
  json: {
    source: 'mock_internship_aggregator',
    results: [
      {
        title: strategy.query.replace(/["()]/g, '').split(' ')[0] + ' Intern (Summer 2027)',
        company: 'BigTech Corp',
        location: 'San Francisco, CA',
        salary_min: 8000,
        salary_max: 9500,
        url: 'https://bigtech.com/internships/1',
        description: 'Join our summer program and learn ' + strategy.query
      },
      {
        title: 'Fall Co-op: ' + strategy.query.replace(/["()]/g, ''),
        company: 'Innovative Startup',
        location: 'Remote',
        salary_min: 5000,
        salary_max: 6000,
        url: 'https://startup.io/interns/2',
        description: 'Hands-on learning with ' + strategy.query
      }
    ]
  }
}];

const crypto = require('crypto');
const allItems = $input.all();
const ctx = $('Parse & Fan Out').item.json.ctx;

const rawJobs = [];

const serpItems = $('Search SerpApi').all();
serpItems.forEach(item => {
  if (item.json.error) return;
  const jobs = item.json.jobs_results || [];
  jobs.forEach(j => {
    rawJobs.push({
      title: j.title,
      company_name: j.company_name,
      location: j.location,
      remote_status: j.location.toLowerCase().includes('remote') ? 'remote' : 'onsite',
      employment_type: 'internship',
      salary_min: null,
      salary_max: null,
      salary_currency: null,
      description: j.description,
      apply_url: j.share_link || j.related_links?.[0]?.link || 'Unknown',
      source: 'serpapi'
    });
  });
});

const adzunaItems = $('Search Adzuna').all();
adzunaItems.forEach(item => {
  if (item.json.error) return;
  const jobs = item.json.results || [];
  jobs.forEach(j => {
    rawJobs.push({
      title: j.title,
      company_name: j.company.display_name,
      location: j.location.display_name,
      remote_status: j.location.display_name.toLowerCase().includes('remote') ? 'remote' : 'onsite',
      employment_type: 'internship',
      salary_min: j.salary_min,
      salary_max: j.salary_max,
      salary_currency: 'USD',
      description: j.description,
      apply_url: j.redirect_url,
      source: 'adzuna'
    });
  });
});

const mockItems = $('Mock Connector').all();
mockItems.forEach(item => {
  if (item.json.error) return;
  const jobs = item.json.results || [];
  jobs.forEach(j => {
    rawJobs.push({
      title: j.title,
      company_name: j.company,
      location: j.location,
      remote_status: j.location.toLowerCase().includes('remote') ? 'remote' : 'onsite',
      employment_type: 'internship',
      salary_min: j.salary_min,
      salary_max: j.salary_max,
      salary_currency: 'USD',
      description: j.description,
      apply_url: j.url,
      source: 'mock'
    });
  });
});

const deduped = [];
const seenHashes = new Set();

rawJobs.forEach(job => {
  if (!job.title || !job.company_name) return;
  // Strong filter to ensure it's actually an internship if using broad APIs
  if (!job.title.toLowerCase().includes('intern') && !job.title.toLowerCase().includes('co-op')) return;

  const hashStr = (job.title.trim().toLowerCase() + '|' + job.company_name.trim().toLowerCase());
  const hash = crypto.createHash('sha256').update(hashStr).digest('hex');

  if (!seenHashes.has(hash)) {
    seenHashes.add(hash);
    job.dedup_hash = hash;
    deduped.push(job);
  }
});

return deduped.map(job => ({
  json: { job, ctx }
}));

const allItems = $input.all();
const ctx = $('Parse & Fan Out').item.json.ctx;

let jobs = allItems.map(i => i.json);
jobs.sort((a, b) => (b.match_score || 0) - (a.match_score || 0));
const topJobs = jobs.slice(0, 20);

const newCtx = { ...ctx };
newCtx.results = newCtx.results || {};
newCtx.results.opportunities = newCtx.results.opportunities || [];
newCtx.results.opportunities.push(...topJobs);
newCtx.agents_completed = [...(newCtx.agents_completed || []), 'internship_search'];

return [{ json: { ctx: newCtx, jobsToInsert: topJobs } }];

