INSERT INTO jobs (company_name, title, location, apply_url, source, match_score, dedup_hash)
VALUES ($1, $2, $3, $4, $5, $6, $7)
ON CONFLICT (dedup_hash) DO UPDATE SET match_score = EXCLUDED.match_score;
